  1	import React, { FC, useEffect, useState } from 'react';
  2	
  3	import HyperConvergedModel from '@kubevirt-ui/kubevirt-api/console/models/HyperConvergedModel';
  4	import NewBadge from '@kubevirt-utils/components/badges/NewBadge/NewBadge';
  5	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
  6	import { DISABLED_GUEST_SYSTEM_LOGS_ACCESS } from '@kubevirt-utils/hooks/useFeatures/constants';
  7	import { useFeatures } from '@kubevirt-utils/hooks/useFeatures/useFeatures';
  8	import { HyperConverged } from '@kubevirt-utils/hooks/useHyperConvergeConfiguration';
  9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 10	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
 11	import {
 12	  Alert,
 13	  AlertVariant,
 14	  PopoverPosition,
 15	  Split,
 16	  SplitItem,
 17	  Switch,
 18	} from '@patternfly/react-core';
 19	
 20	import './guest-system-logs-access.scss';
 21	
 22	type GuestSystemLogsAccessProps = {
 23	  hyperConvergeConfiguration: [hyperConvergeConfig: HyperConverged, loaded: boolean, error: Error];
 24	  newBadge?: boolean;
 25	};
 26	
 27	const GuestSystemLogsAccess: FC<GuestSystemLogsAccessProps> = ({
 28	  hyperConvergeConfiguration,
 29	  newBadge = false,
 30	}) => {
 31	  const { t } = useKubevirtTranslation();
 32	  const [hyperConverge, hyperLoaded] = hyperConvergeConfiguration;
 33	  const { toggleFeature: guestSystemLogsAccessToggle } = useFeatures(
 34	    DISABLED_GUEST_SYSTEM_LOGS_ACCESS,
 35	  );
 36	  const disableSerialConsoleLog =
 37	    hyperConverge?.spec?.virtualMachineOptions?.disableSerialConsoleLog;
 38	
 39	  const [error, setError] = useState<Error>(null);
 40	  const [isChecked, setIsChecked] = useState<boolean>();
 41	
 42	  useEffect(() => {
 43	    guestSystemLogsAccessToggle(!!disableSerialConsoleLog);
 44	    setIsChecked(!disableSerialConsoleLog);
 45	  }, [disableSerialConsoleLog, guestSystemLogsAccessToggle]);
 46	
 47	  const onChange = async (checked: boolean) => {
 48	    try {
 49	      await k8sPatch<HyperConverged>({
 50	        data: [
 51	          {
 52	            op: 'replace',
 53	            path: `/spec/virtualMachineOptions/disableSerialConsoleLog`,
 54	            value: !checked,
 55	          },
 56	        ],
 57	        model: HyperConvergedModel,
 58	        resource: hyperConverge,
 59	      });
 60	      guestSystemLogsAccessToggle(!checked);
 61	      setIsChecked(checked);
 62	    } catch (err) {
 63	      setError(err.message);
 64	    }
 65	  };
 66	
 67	  return (
 68	    <>
 69	      <Split>
 70	        <SplitItem isFilled>
 71	          {t('Enable guest system log access')}{' '}
 72	          <HelpTextIcon
 73	            bodyContent={t(
 74	              "Enables access to the VirtualMachine's guest system log. Wait a few seconds for logging to start before viewing the log.",
 75	            )}
 76	            position={PopoverPosition.bottom}
 77	          />
 78	          {newBadge && <NewBadge />}
 79	        </SplitItem>
 80	        {hyperLoaded && (
 81	          <SplitItem>
 82	            <Switch
 83	              id="guest-system-log-access"
 84	              isChecked={isChecked}
 85	              onChange={(_, checked: boolean) => onChange(checked)}
 86	            />
 87	          </SplitItem>
 88	        )}
 89	      </Split>
 90	      {error && (
 91	        <Alert
 92	          className="GuestSystemLogsAccess--alert"
 93	          isInline
 94	          title={t('Error')}
 95	          variant={AlertVariant.danger}
 96	        >
 97	          {error}
 98	        </Alert>
 99	      )}
100	    </>
101	  );
102	};
103	
104	export default GuestSystemLogsAccess;

